import { JSX } from "react"
import { SectionComponentProps } from "./types"

/** Dot-notation content resolver: resolves "home.hero.headline" to content.home.hero.headline */
export function resolveContent(obj: any, path: string): any {
  if (!obj || !path) return undefined
  return path.split(".").reduce((acc, key) => {
    if (acc && typeof acc === "object" && key in acc) return acc[key]
    return undefined
  }, obj)
}

/** Image resolver: "@img:brand.logo" → "/images/brand/logo.webp" from image manifest */
export function resolveImage(ref: string, images?: Record<string, { src: string; alt?: string }>): { src: string; alt?: string } | undefined {
  if (!ref || !images) return undefined
  // If it has @img: prefix, look up the manifest
  if (ref.startsWith("@img:")) {
    const key = ref.replace("@img:", "")
    const entry = images[key]
    if (!entry) return undefined
    return typeof entry === "string" ? { src: entry } : { src: entry.src, alt: entry.alt }
  }
  // Raw URL
  return typeof ref === "string" ? { src: ref } : undefined
}

/** Check if a conditional section should be enabled */
export function isSectionEnabled(
  enabledWhen: string | undefined,
  content: any
): boolean {
  if (!enabledWhen) return true
  const value = resolveContent(content, enabledWhen)
  if (typeof value === "boolean") return value
  if (Array.isArray(value)) return value.length > 0
  return !!value
}

/** Parse a number from various formats */
export function parseNumber(val: any): number {
  const n = typeof val === "string" ? parseInt(val.replace(/[^0-9.-]/g, ""), 10) : Number(val)
  return isNaN(n) ? 0 : n
}
