import { JSX } from "react"
import { ArrowRight, Sparkles, Shield, CheckCircle, Star, ChevronRight, ArrowUpRight, Users, Award, Building2, Globe, Phone } from "lucide-react"
import Link from "next/link"
import { SectionComponentProps } from "./types"
import { resolveContent, resolveImage, parseNumber } from "./resolve-content"

// ═══════════════════════════════════════════════════════════════════════════════
// REUSABLE SECTION COMPONENTS
// Each component receives SectionComponentProps and renders from JSON content.
// No client-specific business logic. Data-driven and fully configurable.
// ═══════════════════════════════════════════════════════════════════════════════

// ─── HeroSection ──────────────────────────────────────────────────────────────

export function HeroSection({ data, pageContent, images }: SectionComponentProps): JSX.Element {
  const hero = data || pageContent
  if (!hero) return <></>

  const headline = hero.headline || ""
  const subheadline = hero.subheadline || ""
  const primaryCta = hero.primaryCta || { text: "Get Started", href: "#" }
  const secondaryCta = hero.secondaryCta
  const heroImage = hero.image ? resolveImage(hero.image, images) : null

  return (
    <section className="relative min-h-[85vh] flex items-center overflow-hidden bg-gradient-to-br from-gray-900 via-gray-800 to-gray-900">
      {heroImage && (
        <div className="absolute inset-0 opacity-20">
          <img src={heroImage.src} alt={heroImage.alt || ""} className="w-full h-full object-cover" />
        </div>
      )}
      <div className="relative z-10 max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-20">
        <div className="max-w-3xl">
          {hero.badge && (
            <span className="inline-flex items-center gap-2 px-4 py-1.5 rounded-full text-sm font-medium bg-white/10 text-white/90 backdrop-blur-sm mb-6">
              <Sparkles className="w-4 h-4" />
              {hero.badge}
            </span>
          )}
          <h1 className="text-4xl sm:text-5xl md:text-6xl lg:text-7xl font-bold tracking-tight text-white leading-tight">
            {headline}
          </h1>
          {subheadline && (
            <p className="mt-6 text-lg sm:text-xl text-gray-300 max-w-2xl leading-relaxed">
              {subheadline}
            </p>
          )}
          <div className="mt-10 flex flex-wrap gap-4">
            <Link
              href={primaryCta.href}
              className="inline-flex items-center gap-2 px-8 py-4 rounded-xl bg-white text-gray-900 font-semibold hover:bg-gray-100 transition-all shadow-lg hover:shadow-xl"
            >
              {primaryCta.text}
              <ArrowRight className="w-5 h-5" />
            </Link>
            {secondaryCta && (
              <Link
                href={secondaryCta.href}
                className="inline-flex items-center gap-2 px-8 py-4 rounded-xl border border-white/20 text-white font-semibold hover:bg-white/10 transition-all"
              >
                {secondaryCta.text}
              </Link>
            )}
          </div>
        </div>
      </div>
    </section>
  )
}

// ─── StatsSection ─────────────────────────────────────────────────────────────

export function StatsSection({ data }: SectionComponentProps): JSX.Element {
  const stats = Array.isArray(data) ? data : data?.stats || []
  if (!stats.length) return <></>

  return (
    <section className="py-16 bg-white dark:bg-gray-900">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="grid grid-cols-2 md:grid-cols-4 gap-8">
          {stats.map((stat: any, i: number) => (
            <div key={i} className="text-center">
              <div className="text-3xl sm:text-4xl font-bold text-gray-900 dark:text-white">
                {stat.value}
              </div>
              <div className="mt-2 text-sm text-gray-500 dark:text-gray-400">
                {stat.label}
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  )
}

// ─── TrustSection ─────────────────────────────────────────────────────────────

export function TrustSection({ data, pageContent }: SectionComponentProps): JSX.Element {
  const trust = data || pageContent?.trust
  if (!trust) return <></>

  const items = trust.items || []
  return (
    <section className="py-16 bg-gray-50 dark:bg-gray-800/50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        {trust.headline && (
          <h2 className="text-2xl sm:text-3xl font-bold text-center mb-12 text-gray-900 dark:text-white">
            {trust.headline}
          </h2>
        )}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8">
          {items.map((item: any, i: number) => (
            <div key={i} className="bg-white dark:bg-gray-800 rounded-xl p-6 shadow-sm border border-gray-100 dark:border-gray-700">
              <div className="w-12 h-12 rounded-lg bg-blue-100 dark:bg-blue-900/30 flex items-center justify-center mb-4">
                {item.icon === "shield" && <Shield className="w-6 h-6 text-blue-600 dark:text-blue-400" />}
                {item.icon === "check" && <CheckCircle className="w-6 h-6 text-blue-600 dark:text-blue-400" />}
                {item.icon === "star" && <Star className="w-6 h-6 text-blue-600 dark:text-blue-400" />}
                {item.icon === "users" && <Users className="w-6 h-6 text-blue-600 dark:text-blue-400" />}
                {!item.icon && <CheckCircle className="w-6 h-6 text-blue-600 dark:text-blue-400" />}
              </div>
              <h3 className="text-lg font-semibold text-gray-900 dark:text-white">{item.title}</h3>
              <p className="mt-2 text-sm text-gray-500 dark:text-gray-400">{item.description}</p>
            </div>
          ))}
        </div>
      </div>
    </section>
  )
}

// ─── ProgramsSection ──────────────────────────────────────────────────────────

export function ProgramsSection({ data, pageContent }: SectionComponentProps): JSX.Element {
  const section = data || pageContent?.programs
  if (!section) return <></>
  const programs = section.programs || section.items || []
  if (!programs.length) return <></>

  return (
    <section className="py-16 bg-white dark:bg-gray-900">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        {section.headline && (
          <div className="text-center mb-12">
            <h2 className="text-2xl sm:text-3xl font-bold text-gray-900 dark:text-white">{section.headline}</h2>
            {section.subheadline && <p className="mt-4 text-gray-500 dark:text-gray-400 max-w-2xl mx-auto">{section.subheadline}</p>}
          </div>
        )}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {programs.map((program: any, i: number) => (
            <div
              key={i}
              className={`group relative rounded-2xl p-8 transition-all border ${
                program.featured
                  ? "bg-blue-600 text-white border-blue-500 shadow-xl"
                  : "bg-white dark:bg-gray-800 border-gray-200 dark:border-gray-700 hover:shadow-lg"
              }`}
            >
              {program.featured && (
                <span className="absolute -top-3 right-6 px-4 py-1 rounded-full text-xs font-semibold bg-yellow-400 text-gray-900">
                  Popular
                </span>
              )}
              {program.icon && <div className="text-3xl mb-4">{program.icon}</div>}
              <h3 className={`text-xl font-bold ${program.featured ? "text-white" : "text-gray-900 dark:text-white"}`}>
                {program.title}
              </h3>
              {program.price && (
                <p className={`mt-2 text-sm ${program.featured ? "text-blue-100" : "text-gray-500 dark:text-gray-400"}`}>
                  {program.price}
                </p>
              )}
              <ul className="mt-6 space-y-3">
                {(program.benefits || program.features || []).map((b: string, j: number) => (
                  <li key={j} className="flex items-start gap-2 text-sm">
                    <CheckCircle className={`w-4 h-4 mt-0.5 ${program.featured ? "text-white" : "text-blue-600 dark:text-blue-400"}`} />
                    <span className={program.featured ? "text-white/90" : "text-gray-600 dark:text-gray-300"}>{b}</span>
                  </li>
                ))}
              </ul>
              {program.cta && (
                <Link
                  href={program.cta.href || "#"}
                  className={`mt-8 inline-flex items-center gap-2 text-sm font-semibold ${
                    program.featured ? "text-white" : "text-blue-600 dark:text-blue-400"
                  }`}
                >
                  {program.cta.text} <ArrowUpRight className="w-4 h-4" />
                </Link>
              )}
            </div>
          ))}
        </div>
      </div>
    </section>
  )
}

// ─── ServicesSection ──────────────────────────────────────────────────────────

export function ServicesSection({ data, pageContent }: SectionComponentProps): JSX.Element {
  const section = data || pageContent?.services
  if (!section) return <></>
  const services = section.services || section.items || []
  if (!services.length) return <></>

  return (
    <section className="py-16 bg-gray-50 dark:bg-gray-800/50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        {section.headline && (
          <div className="text-center mb-12">
            <h2 className="text-2xl sm:text-3xl font-bold text-gray-900 dark:text-white">{section.headline}</h2>
            {section.subheadline && <p className="mt-4 text-gray-500 dark:text-gray-400 max-w-2xl mx-auto">{section.subheadline}</p>}
          </div>
        )}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
          {services.map((service: any, i: number) => (
            <div
              key={i}
              className="group bg-white dark:bg-gray-800 rounded-xl p-6 shadow-sm border border-gray-100 dark:border-gray-700 hover:shadow-md transition-all"
            >
              <div className="w-12 h-12 rounded-lg bg-blue-100 dark:bg-blue-900/30 flex items-center justify-center mb-4 group-hover:scale-110 transition-transform">
                <Building2 className="w-6 h-6 text-blue-600 dark:text-blue-400" />
              </div>
              <h3 className="text-lg font-semibold text-gray-900 dark:text-white">{service.title}</h3>
              <p className="mt-2 text-sm text-gray-500 dark:text-gray-400">{service.description}</p>
              {service.cta && (
                <Link href={service.cta.href || "#"} className="mt-4 inline-flex items-center gap-1 text-sm font-medium text-blue-600 dark:text-blue-400 hover:underline">
                  {service.cta.text} <ChevronRight className="w-3 h-3" />
                </Link>
              )}
            </div>
          ))}
        </div>
      </div>
    </section>
  )
}

// ─── WhyCountrySection ────────────────────────────────────────────────────────

export function WhyCountrySection({ data, pageContent }: SectionComponentProps): JSX.Element {
  const section = data || pageContent?.whyParaguay || pageContent?.whyCountry
  if (!section) return <></>
  const reasons = section.reasons || section.items || []
  if (!reasons.length) return <></>

  return (
    <section className="py-16 bg-white dark:bg-gray-900">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        {section.headline && (
          <div className="text-center mb-12">
            <h2 className="text-2xl sm:text-3xl font-bold text-gray-900 dark:text-white">{section.headline}</h2>
            {section.subheadline && <p className="mt-4 text-gray-500 dark:text-gray-400">{section.subheadline}</p>}
          </div>
        )}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {reasons.map((reason: any, i: number) => (
            <div key={i} className="flex gap-4">
              <div className="flex-shrink-0 w-12 h-12 rounded-full bg-green-50 dark:bg-green-900/20 flex items-center justify-center">
                <span className="text-green-600 dark:text-green-400 font-bold">{String(i + 1).padStart(2, "0")}</span>
              </div>
              <div>
                <h3 className="font-semibold text-gray-900 dark:text-white">{reason.title}</h3>
                <p className="mt-1 text-sm text-gray-500 dark:text-gray-400">{reason.description}</p>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  )
}

// ─── FeaturesSection ──────────────────────────────────────────────────────────

export function FeaturesSection({ data, pageContent }: SectionComponentProps): JSX.Element {
  const section = data || pageContent?.features
  if (!section) return <></>
  const features = section.features || section.items || []
  if (!features.length) return <></>

  return (
    <section className="py-16 bg-gray-50 dark:bg-gray-800/50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        {section.headline && (
          <div className="text-center mb-12">
            <h2 className="text-2xl sm:text-3xl font-bold text-gray-900 dark:text-white">{section.headline}</h2>
            {section.subheadline && <p className="mt-4 text-gray-500 dark:text-gray-400 max-w-2xl mx-auto">{section.subheadline}</p>}
          </div>
        )}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
          {features.map((feature: any, i: number) => (
            <div key={i} className="bg-white dark:bg-gray-800 rounded-xl p-6 shadow-sm border border-gray-100 dark:border-gray-700">
              {feature.icon && <div className="text-2xl mb-3">{feature.icon}</div>}
              <h3 className="font-semibold text-gray-900 dark:text-white">{feature.title}</h3>
              <p className="mt-2 text-sm text-gray-500 dark:text-gray-400">{feature.description}</p>
            </div>
          ))}
        </div>
      </div>
    </section>
  )
}

// ─── ProcessSection ───────────────────────────────────────────────────────────

export function ProcessSection({ data, pageContent }: SectionComponentProps): JSX.Element {
  const section = data || pageContent?.process
  if (!section) return <></>
  const steps = section.steps || section.items || []
  if (!steps.length) return <></>

  return (
    <section className="py-16 bg-white dark:bg-gray-900">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        {section.headline && (
          <div className="text-center mb-12">
            <h2 className="text-2xl sm:text-3xl font-bold text-gray-900 dark:text-white">{section.headline}</h2>
            {section.subheadline && <p className="mt-4 text-gray-500 dark:text-gray-400 max-w-2xl mx-auto">{section.subheadline}</p>}
          </div>
        )}
        <div className="relative">
          <div className="hidden lg:block absolute left-1/2 top-0 bottom-0 w-0.5 bg-gray-200 dark:bg-gray-700 -translate-x-1/2" />
          <div className="space-y-12">
            {steps.map((step: any, i: number) => (
              <div key={i} className={`relative flex flex-col lg:flex-row items-center gap-8 ${i % 2 === 0 ? "lg:flex-row" : "lg:flex-row-reverse"}`}>
                <div className="flex-1">
                  <div className="bg-white dark:bg-gray-800 rounded-xl p-6 shadow-sm border border-gray-100 dark:border-gray-700">
                    <span className="inline-flex items-center justify-center w-8 h-8 rounded-full bg-blue-600 text-white text-sm font-bold mb-3">
                      {i + 1}
                    </span>
                    <h3 className="text-lg font-semibold text-gray-900 dark:text-white">{step.title}</h3>
                    <p className="mt-2 text-sm text-gray-500 dark:text-gray-400">{step.description}</p>
                  </div>
                </div>
                <div className="hidden lg:flex w-8 h-8 rounded-full bg-blue-100 dark:bg-blue-900/30 items-center justify-center z-10">
                  <div className="w-3 h-3 rounded-full bg-blue-600" />
                </div>
                <div className="flex-1 lg:invisible" />
              </div>
            ))}
          </div>
        </div>
      </div>
    </section>
  )
}

// ─── TestimonialsSection ──────────────────────────────────────────────────────

export function TestimonialsSection({ data, pageContent }: SectionComponentProps): JSX.Element {
  const section = data || pageContent?.testimonials
  if (!section) return <></>
  const testimonials = section.testimonials || section.items || []
  if (!testimonials.length) return <></>

  return (
    <section className="py-16 bg-gray-50 dark:bg-gray-800/50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        {section.headline && (
          <div className="text-center mb-12">
            <h2 className="text-2xl sm:text-3xl font-bold text-gray-900 dark:text-white">{section.headline}</h2>
          </div>
        )}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {testimonials.map((t: any, i: number) => (
