import { JSX, useState } from "react"
import { ChevronDown, Search, Phone, Mail, MapPin, Clock, Calendar, ArrowRight, ChevronRight, Star, ExternalLink } from "lucide-react"
import Link from "next/link"
import { SectionComponentProps } from "./types"
import { resolveContent, resolveImage } from "./resolve-content"

// ═══════════════════════════════════════════════════════════════════════════════
// EXTRA SECTION COMPONENTS (16+ components)
// These are commonly needed but more niche than the core 11 above.
// ═══════════════════════════════════════════════════════════════════════════════

// ─── FaqSection ────────────────────────────────────────────────────────────────

export function FaqSection({ data, pageContent }: SectionComponentProps): JSX.Element {
  const section = data || pageContent?.faq
  if (!section) return <></>
  const faqs = section.faqs || section.items || []
  if (!faqs.length) return <></>

  return (
    <section className="py-16 bg-white dark:bg-gray-900">
      <div className="max-w-3xl mx-auto px-4 sm:px-6 lg:px-8">
        {section.headline && (
          <h2 className="text-2xl sm:text-3xl font-bold text-center mb-8 text-gray-900 dark:text-white">{section.headline}</h2>
        )}
        <div className="space-y-3">
          {faqs.map((faq: any, i: number) => (
            <FaqItem key={i} question={faq.question} answer={faq.answer} />
          ))}
        </div>
      </div>
    </section>
  )
}

function FaqItem({ question, answer }: { question: string; answer: string }): JSX.Element {
  const [open, setOpen] = useState(false)
  return (
    <div className="border border-gray-200 dark:border-gray-700 rounded-xl overflow-hidden">
      <button
        onClick={() => setOpen(!open)}
        className="w-full flex items-center justify-between px-6 py-4 text-left bg-white dark:bg-gray-800 hover:bg-gray-50 dark:hover:bg-gray-750 transition-colors"
      >
        <span className="font-medium text-gray-900 dark:text-white pr-4">{question}</span>
        <ChevronDown className={`w-5 h-5 text-gray-400 transition-transform flex-shrink-0 ${open ? "rotate-180" : ""}`} />
      </button>
      {open && (
        <div className="px-6 pb-4 bg-gray-50 dark:bg-gray-800/50">
          <p className="text-gray-600 dark:text-gray-300 text-sm leading-relaxed">{answer}</p>
        </div>
      )}
    </div>
  )
}

// ─── FaqSearchSection ─────────────────────────────────────────────────────────

export function FaqSearchSection({ data, pageContent }: SectionComponentProps): JSX.Element {
  const section = data || pageContent?.faq
  if (!section) return <></>
  const faqs = section.faqs || section.items || []
  const [search, setSearch] = useState("")
  const [openId, setOpenId] = useState<number | null>(null)

  const filtered = faqs.filter((f: any) =>
    !search || f.question?.toLowerCase().includes(search.toLowerCase()) || f.answer?.toLowerCase().includes(search.toLowerCase())
  )

  return (
    <section className="py-16 bg-white dark:bg-gray-900">
      <div className="max-w-3xl mx-auto px-4 sm:px-6 lg:px-8">
        {section.headline && (
          <h2 className="text-2xl sm:text-3xl font-bold text-center mb-4 text-gray-900 dark:text-white">{section.headline}</h2>
        )}
        <div className="relative mb-8">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
          <input
            type="text"
            placeholder={section.searchPlaceholder || "Search..."}
            value={search}
            onChange={(e) => { setSearch(e.target.value); setOpenId(null) }}
            className="w-full pl-12 pr-4 py-3 rounded-xl border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 text-gray-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
          />
        </div>
        <div className="space-y-2">
          {filtered.map((faq: any, i: number) => (
            <div key={i} className="border border-gray-200 dark:border-gray-700 rounded-xl overflow-hidden">
              <button
                onClick={() => setOpenId(openId === i ? null : i)}
                className="w-full flex items-center justify-between px-6 py-4 text-left bg-white dark:bg-gray-800 hover:bg-gray-50"
              >
                <span className="font-medium text-gray-900 dark:text-white">{faq.question}</span>
                <ChevronDown className={`w-4 h-4 text-gray-400 transition-transform ${openId === i ? "rotate-180" : ""}`} />
              </button>
              {openId === i && (
                <div className="px-6 pb-4 bg-gray-50 dark:bg-gray-800/50">
                  <p className="text-gray-600 dark:text-gray-300 text-sm">{faq.answer}</p>
                </div>
              )}
            </div>
          ))}
        </div>
      </div>
    </section>
  )
}

// ─── BlogSection ──────────────────────────────────────────────────────────────

export function BlogSection({ data, pageContent, locale }: SectionComponentProps): JSX.Element {
  const section = data || pageContent?.blog
  if (!section) return <></>
  const posts = section.posts || section.items || []
  if (!posts.length) return <></>

  return (
    <section className="py-16 bg-gray-50 dark:bg-gray-800/50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        {section.headline && (
          <div className="flex items-center justify-between mb-8">
            <h2 className="text-2xl sm:text-3xl font-bold text-gray-900 dark:text-white">{section.headline}</h2>
            {section.viewAll && (
              <Link href={section.viewAll.href || "/blog"} className="text-sm font-medium text-blue-600 dark:text-blue-400 hover:underline">
                {section.viewAll.text} <ArrowRight className="w-3 h-3 inline" />
              </Link>
            )}
          </div>
        )}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {posts.slice(0, 6).map((post: any, i: number) => (
            <Link key={i} href={post.href || `/blog/${post.slug}`} className="group bg-white dark:bg-gray-800 rounded-xl overflow-hidden shadow-sm border border-gray-100 dark:border-gray-700 hover:shadow-md transition-all">
              {post.image && (
                <div className="aspect-[16/9] bg-gray-100 dark:bg-gray-700 overflow-hidden">
                  <img src={typeof post.image === "string" ? post.image : post.image.src} alt={post.title} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-300" />
                </div>
              )}
              <div className="p-5">
                {post.category && <span className="text-xs font-semibold text-blue-600 dark:text-blue-400 uppercase tracking-wider">{post.category}</span>}
                <h3 className="mt-1 font-semibold text-gray-900 dark:text-white group-hover:text-blue-600 dark:group-hover:text-blue-400 transition-colors">{post.title}</h3>
                <p className="mt-2 text-sm text-gray-500 dark:text-gray-400 line-clamp-2">{post.excerpt || post.description}</p>
                <div className="mt-3 flex items-center gap-3 text-xs text-gray-400">
                  {post.date && <span>{post.date}</span>}
                  {post.readTime && <span>· {post.readTime}</span>}
                </div>
              </div>
            </Link>
          ))}
        </div>
      </div>
    </section>
  )
}

// ─── TeamSection ──────────────────────────────────────────────────────────────

export function TeamSection({ data, pageContent, images }: SectionComponentProps): JSX.Element {
  const section = data || pageContent?.team
  if (!section) return <></>
  const members = section.members || section.items || []
  if (!members.length) return <></>

  return (
    <section className="py-16 bg-white dark:bg-gray-900">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        {section.headline && (
          <div className="text-center mb-12">
            <h2 className="text-2xl sm:text-3xl font-bold text-gray-900 dark:text-white">{section.headline}</h2>
            {section.subheadline && <p className="mt-4 text-gray-500 dark:text-gray-400">{section.subheadline}</p>}
          </div>
        )}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8">
          {members.map((member: any, i: number) => (
            <div key={i} className="text-center">
              <div className="w-24 h-24 rounded-full bg-gray-100 dark:bg-gray-700 mx-auto overflow-hidden mb-4">
                {member.image ? (
                  <img src={typeof member.image === "string" ? member.image : member.image.src} alt={member.name} className="w-full h-full object-cover" />
                ) : (
                  <div className="w-full h-full flex items-center justify-center text-2xl font-bold text-gray-400">
                    {member.name?.charAt(0) || "?"}
                  </div>
                )}
              </div>
              <h3 className="font-semibold text-gray-900 dark:text-white">{member.name}</h3>
              {member.role && <p className="text-sm text-gray-500 dark:text-gray-400">{member.role}</p>}
            </div>
          ))}
        </div>
      </div>
    </section>
  )
}

// ─── StorySection ─────────────────────────────────────────────────────────────

export function StorySection({ data, pageContent }: SectionComponentProps): JSX.Element {
  const section = data || pageContent?.story
  if (!section) return <></>

  return (
    <section className="py-16 bg-gray-50 dark:bg-gray-800/50">
      <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-12 items-center">
          {section.image && (
            <div className="rounded-2xl overflow-hidden">
              <img src={typeof section.image === "string" ? section.image : section.image.src} alt={section.headline || ""} className="w-full h-auto object-cover" />
            </div>
          )}
          <div>
            {section.headline && <h2 className="text-2xl sm:text-3xl font-bold text-gray-900 dark:text-white">{section.headline}</h2>}
            {section.text?.map((p: string, i: number) => (
              <p key={i} className="mt-4 text-gray-600 dark:text-gray-300 leading-relaxed">{p}</p>
            ))}
            {section.cta && (
              <Link href={section.cta.href || "#"} className="mt-6 inline-flex items-center gap-2 text-blue-600 dark:text-blue-400 font-medium hover:underline">
                {section.cta.text} <ArrowRight className="w-4 h-4" />
              </Link>
            )}
          </div>
        </div>
      </div>
    </section>
  )
