          <div className="text-center mb-12">
            <h2 className="text-2xl sm:text-3xl font-bold text-gray-900 dark:text-white">{section.headline}</h2>
          </div>
        )}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
          {pillars.map((pillar: any, i: number) => (
            <div key={i} className="relative p-8 rounded-2xl bg-gradient-to-br from-blue-50 to-white dark:from-gray-800 dark:to-gray-900 border border-blue-100 dark:border-gray-700">
              <div className="text-4xl mb-4">{pillar.icon || "✦"}</div>
              <h3 className="text-xl font-bold text-gray-900 dark:text-white">{pillar.title}</h3>
              <p className="mt-3 text-gray-500 dark:text-gray-400 text-sm leading-relaxed">{pillar.description}</p>
            </div>
          ))}
        </div>
      </div>
