// ─── NewsletterSection ────────────────────────────────────────────────────────

export function NewsletterSection({ data, pageContent }: SectionComponentProps): JSX.Element {
  const section = data || pageContent?.newsletter
  if (!section) return <></>

  return (
    <section className="py-16 bg-gradient-to-r from-blue-600 to-blue-800">
      <div className="max-w-2xl mx-auto px-4 sm:px-6 lg:px-8 text-center">
        <h2 className="text-2xl font-bold text-white">{section.headline || section.title}</h2>
        {section.description && <p className="mt-4 text-blue-100">{section.description}</p>}
        <form className="mt-8 flex gap-3 max-w-md mx-auto" onSubmit={(e) => e.preventDefault()}>
          <input
            type="email"
            placeholder={section.placeholder || "[REDACTED_EMAIL]"}
