// ─── ContactDetailsSection ────────────────────────────────────────────────────

export function ContactDetailsSection({ data, pageContent }: SectionComponentProps): JSX.Element {
  const section = data || pageContent?.contact
  if (!section) return <></>

  const items = [
    { icon: Phone, label: "Phone", value: section.phone, href: section.phone ? `tel:${section.phone}` : undefined },
    { icon: Mail, label: "Email", value: section.email, href: section.email ? `mailto:${section.email}` : undefined },
    { icon: MapPin, label: "Address", value: section.address },
    { icon: Clock, label: "Hours", value: section.hours },
  ].filter((i) => i.value)

  return (
    <section className="py-16 bg-gray-50 dark:bg-gray-800/50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        {section.headline && (
          <h2 className="text-2xl sm:text-3xl font-bold text-center mb-12 text-gray-900 dark:text-white">{section.headline}</h2>
        )}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 max-w-4xl mx-auto">
          {items.map((item, i) => {
            const IconComp = item.icon
            return (
              <div key={i} className="bg-white dark:bg-gray-800 rounded-xl p-6 text-center shadow-sm border border-gray-100 dark:border-gray-700">
                <div className="w-12 h-12 rounded-full bg-blue-100 dark:bg-blue-900/30 flex items-center justify-center mx-auto mb-4">
                  <IconComp className="w-5 h-5 text-blue-600 dark:text-blue-400" />
                </div>
                <div className="text-sm font-medium text-gray-900 dark:text-white">{item.label}</div>
                {item.href ? (
                  <a href={item.href} className="mt-1 text-sm text-blue-600 dark:text-blue-400 hover:underline block">{item.value}</a>
                ) : (
                  <div className="mt-1 text-sm text-gray-500 dark:text-gray-400">{item.value}</div>
                )}
              </div>
            )
          })}
        </div>
      </div>
    </section>
  )
}

// ─── GallerySection ───────────────────────────────────────────────────────────

export function GallerySection({ data, pageContent, images }: SectionComponentProps): JSX.Element {
  const section = data || pageContent?.gallery
  if (!section) return <></>
  const galleryItems = section.items || section.images || []
  if (!galleryItems.length) return <></>

  return (
    <section className="py-16 bg-white dark:bg-gray-900">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        {section.headline && (
          <h2 className="text-2xl sm:text-3xl font-bold text-center mb-8 text-gray-900 dark:text-white">{section.headline}</h2>
        )}
        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4">
          {galleryItems.map((item: any, i: number) => {
            const img = item.image ? resolveImage(item.image, images) : null
            const src = img?.src || item.src || item.image
            return (
              <div key={i} className="aspect-square rounded-xl overflow-hidden bg-gray-100 dark:bg-gray-800">
                {src && <img src={src} alt={item.alt || item.title || ""} className="w-full h-full object-cover hover:scale-105 transition-transform duration-300" />}
              </div>
            )
          })}
        </div>
      </div>
    </section>
  )
}

// ─── ComparisonSection ────────────────────────────────────────────────────────

export function ComparisonSection({ data, pageContent }: SectionComponentProps): JSX.Element {
  const section = data || pageContent?.comparison
  if (!section) return <></>
  const features = section.features || []
  if (!features.length) return <></>

  return (
    <section className="py-16 bg-gray-50 dark:bg-gray-800/50">
      <div className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8">
        {section.headline && (
          <h2 className="text-2xl sm:text-3xl font-bold text-center mb-4 text-gray-900 dark:text-white">{section.headline}</h2>
        )}
        {section.subheadline && <p className="text-center text-gray-500 dark:text-gray-400 mb-8">{section.subheadline}</p>}
        <div className="overflow-x-auto">
          <table className="w-full text-sm">
            <thead>
              <tr className="border-b border-gray-200 dark:border-gray-700">
                <th className="text-left py-4 px-4 font-semibold text-gray-900 dark:text-white">{section.ourLabel || "Us"}</th>
                <th className="text-left py-4 px-4 font-semibold text-gray-500">{section.otherLabel || "Others"}</th>
              </tr>
            </thead>
            <tbody>
              {features.map((f: any, i: number) => (
                <tr key={i} className="border-b border-gray-100 dark:border-gray-800">
                  <td className="py-3 px-4 text-gray-900 dark:text-white">{f.us || f.positive}</td>
                  <td className="py-3 px-4 text-gray-500">{f.other || f.negative}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </section>
  )
}

// ─── GlossarySection ──────────────────────────────────────────────────────────

export function GlossarySection({ data, pageContent }: SectionComponentProps): JSX.Element {
  const section = data || pageContent?.glossary
  if (!section) return <></>
  const terms = section.terms || section.items || []
  if (!terms.length) return <></>

