// ─── HighlightSection ─────────────────────────────────────────────────────────

export function HighlightSection({ data, pageContent }: SectionComponentProps): JSX.Element {
  const section = data || pageContent?.highlight
  if (!section) return <></>

  return (
    <section className="py-16 bg-blue-600">
      <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 text-center">
        <p className="text-xl sm:text-2xl font-semibold text-white leading-relaxed">
          {section.quote || section.text}
        </p>
        {section.author && (
          <p className="mt-6 text-blue-200 font-medium">— {section.author}</p>
        )}
      </div>
    </section>
  )
}

// ─── BookingEmbedSection ──────────────────────────────────────────────────────

export function BookingEmbedSection({ data, pageContent }: SectionComponentProps): JSX.Element {
  const section = data || pageContent?.booking
  if (!section?.calendlyUrl && !section?.url) return <></>

  return (
    <section className="py-16 bg-gray-50 dark:bg-gray-800/50">
      <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8">
        {section.headline && <h2 className="text-2xl sm:text-3xl font-bold text-center mb-8 text-gray-900 dark:text-white">{section.headline}</h2>}
        <div className="rounded-xl overflow-hidden shadow-lg">
          <iframe
            src={section.calendlyUrl || section.url}
            width="100%"
            height="700"
            frameBorder="0"
            title="Schedule a consultation"
          />
        </div>
      </div>
    </section>
  )
}

// ─── CaseStudySection ─────────────────────────────────────────────────────────

export function CaseStudySection({ data, pageContent }: SectionComponentProps): JSX.Element {
  const section = data || pageContent?.caseStudy
  if (!section) return <></>
  const studies = section.studies || section.items || []
  if (!studies.length) return <></>

  return (
    <section className="py-16 bg-white dark:bg-gray-900">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="text-center mb-12">
          <h2 className="text-2xl sm:text-3xl font-bold text-gray-900 dark:text-white">{section.headline}</h2>
          {section.subheadline && <p className="mt-4 text-gray-500 dark:text-gray-400">{section.subheadline}</p>}
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          {studies.map((study: any, i: number) => (
            <div key={i} className="rounded-xl border border-gray-100 dark:border-gray-700 overflow-hidden bg-white dark:bg-gray-800 shadow-sm">
              {study.image && (
                <div className="aspect-[16/9] bg-gray-100 dark:bg-gray-700">
                  <img src={study.image.src || study.image} alt={study.title} className="w-full h-full object-cover" />
                </div>
              )}
              <div className="p-6">
                <span className="text-xs font-semibold text-blue-600 dark:text-blue-400 uppercase">{study.category}</span>
                <h3 className="mt-1 text-lg font-semibold text-gray-900 dark:text-white">{study.title}</h3>
                <p className="mt-2 text-sm text-gray-500 dark:text-gray-400">{study.description}</p>
                {study.results && (
                  <div className="mt-4 flex gap-4">
                    {study.results.map((r: any, j: number) => (
                      <div key={j}>
                        <div className="text-lg font-bold text-blue-600 dark:text-blue-400">{r.metric}</div>
                        <div className="text-xs text-gray-500">{r.label}</div>
                      </div>
                    ))}
                  </div>
                )}
                {study.cta && (
                  <Link href={study.cta.href || "#"} className="mt-4 inline-flex items-center gap-1 text-sm font-medium text-blue-600 dark:text-blue-400 hover:underline">
                    {study.cta.text} <ExternalLink className="w-3 h-3" />
                  </Link>
                )}
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  )
}

// ─── ServiceDetailSection ─────────────────────────────────────────────────────

export function ServiceDetailSection({ data, pageContent }: SectionComponentProps): JSX.Element {
  const section = data || pageContent
  if (!section) return <></>

  return (
    <section className="py-16 bg-white dark:bg-gray-900">
      <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8">
        {section.description && <p className="text-lg text-gray-600 dark:text-gray-300 leading-relaxed">{section.description}</p>}
        {section.details && (
          <ul className="mt-8 space-y-4">
            {section.details.map((d: any, i: number) => (
              <li key={i} className="flex items-start gap-3">
                <CheckCircle className="w-5 h-5 text-green-500 flex-shrink-0 mt-0.5" />
                <span className="text-gray-700 dark:text-gray-300">{typeof d === "string" ? d : d.text}</span>
              </li>
            ))}
          </ul>
        )}
      </div>
    </section>
  )
}

// ─── GenericSection (fallback for unknown section types) ─────────────────────

export function GenericSection({ data, pageContent }: SectionComponentProps): JSX.Element {
  const section = data || pageContent
  if (!section) return <></>

  const items = section.items || section.cards || section.features || []
  const hasItems = Array.isArray(items) && items.length > 0

  return (
    <section className="py-12 bg-white dark:bg-gray-900">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        {section.headline && <h2 className="text-2xl font-bold text-gray-900 dark:text-white mb-6">{section.headline}</h2>}
        {section.text && <p className="text-gray-600 dark:text-gray-300">{section.text}</p>}
        {hasItems && (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 mt-6">
            {items.map((item: any, i: number) => (
              <div key={i} className="p-4 rounded-lg border border-gray-100 dark:border-gray-700 bg-gray-50 dark:bg-gray-800/50">
                {item.title && <h3 className="font-semibold text-gray-900 dark:text-white">{item.title}</h3>}
                {item.description && <p className="mt-1 text-sm text-gray-500">{item.description}</p>}
              </div>
            ))}
          </div>
        )}
      </div>
    </section>
  )
}

// ─── PrivacyAccordion (for legal/privacy pages) ──────────────────────────────

export function PrivacyAccordion({ data, pageContent }: SectionComponentProps): JSX.Element {
  const sections = data || pageContent?.sections || []
  if (!sections.length && !data) {
    // Try to use pageContent directly if no sections key
    if (!pageContent) return <></>
    const content = pageContent
    if (!content.title && !content.lastUpdated) return <></>
    return (
      <section className="py-16 bg-white dark:bg-gray-900">
        <div className="max-w-3xl mx-auto px-4 sm:px-6 lg:px-8">
          {content.title && <h1 className="text-3xl font-bold text-gray-900 dark:text-white">{content.title}</h1>}
          {content.lastUpdated && <p className="mt-2 text-sm text-gray-500">Last updated: {content.lastUpdated}</p>}
          {content.sections?.map((s: any, i: number) => (
            <div key={i} className="mt-8">
              <h2 className="text-xl font-semibold text-gray-900 dark:text-white">{s.title}</h2>
              {s.body?.map((p: string, j: number) => (
                <p key={j} className="mt-2 text-gray-600 dark:text-gray-300">{p}</p>
              ))}
            </div>
          ))}
        </div>
      </section>
    )
  }

  return (
    <section className="py-16 bg-white dark:bg-gray-900">
      <div className="max-w-3xl mx-auto px-4 sm:px-6 lg:px-8">
        <h2 className="text-2xl font-bold text-gray-900 dark:text-white mb-8">{data?.headline || "Legal Information"}</h2>
        <div className="space-y-4">
          {sections.map((sec: any, i: number) => (
            <div key={i} className="border border-gray-200 dark:border-gray-700 rounded-xl p-6">
              <h3 className="font-semibold text-gray-900 dark:text-white">{sec.title}</h3>
              {sec.body?.map((p: string, j: number) => (
                <p key={j} className="mt-2 text-sm text-gray-600 dark:text-gray-300">{p}</p>
              ))}
            </div>
          ))}
        </div>
      </div>
    </section>
  )
}
