import { resolveContent, isSectionEnabled } from "./resolve-content"

// ═══════════════════════════════════════════════════════════════════════════════
// SECTION REGISTRY
// Map section IDs to React components. Add new sections here.
// ═══════════════════════════════════════════════════════════════════════════════

export const DEFAULT_SECTIONS: SectionRegistry = {
  // Core sections (from sections.tsx)
  "hero": HeroSection,
  "hero-section": HeroSection,
  "stats": StatsSection,
  "stats-grid": StatsSection,
  "trust-signals": TrustSection,
