export function websiteSchema(data: { name: string; url: string; description?: string; searchUrl?: string }) {
  return {
    "@context": "https://schema.org",
    "@type": "WebSite",
    name: data.name,
    url: data.url,
    ...(data.description && { description: data.description }),
    ...(data.searchUrl && {
